import React, { useState, useRef, useEffect } from 'react';

let n = 0;
const uid = () => `m${++n}`;

export default function ChatUI() {
  const [messages, setMessages] = useState([
    { id: uid(), from: 'them', text: 'Hey! Ask me anything.' },
  ]);
  const [draft, setDraft] = useState('');
  const endRef = useRef(null);

  useEffect(() => {
    if (endRef.current) endRef.current.scrollIntoView({ behavior: 'smooth' });
  }, [messages]);

  const send = () => {
    const t = draft.trim();
    if (!t) return;
    setMessages((m) => [...m, { id: uid(), from: 'me', text: t }]);
    setDraft('');
    setTimeout(() => {
      setMessages((m) => [...m, { id: uid(), from: 'them', text: `Echo: ${t}` }]);
    }, 600);
  };

  return (
    <div style={{ width: 340, border: '1px solid #cbd5e1', borderRadius: 12, overflow: 'hidden' }}>
      <div style={{ height: 280, overflowY: 'auto', padding: 12, background: '#f8fafc' }}>
        {messages.map((m) => (
          <div key={m.id} style={{ display: 'flex', justifyContent: m.from === 'me' ? 'flex-end' : 'flex-start', marginBottom: 8 }}>
            <div
              style={{
                maxWidth: '75%',
                padding: '8px 12px',
                borderRadius: 14,
                background: m.from === 'me' ? '#2563eb' : '#e2e8f0',
                color: m.from === 'me' ? '#fff' : '#111',
              }}
            >
              {m.text}
            </div>
          </div>
        ))}
        <div ref={endRef} />
      </div>
      <div style={{ display: 'flex', gap: 8, padding: 10, borderTop: '1px solid #e5e7eb' }}>
        <input
          value={draft}
          onChange={(e) => setDraft(e.target.value)}
          onKeyDown={(e) => e.key === 'Enter' && send()}
          placeholder="Type a message…"
          style={{ flex: 1, padding: 8, border: '1px solid #cbd5e1', borderRadius: 8 }}
        />
        <button onClick={send} style={{ padding: '8px 16px', cursor: 'pointer', background: '#2563eb', color: '#fff', border: 'none', borderRadius: 8 }}>Send</button>
      </div>
    </div>
  );
}

