import { Component, ViewChild, ElementRef, AfterViewChecked } from '@angular/core';
import { NgModule } from '@angular/core';
import { BrowserModule } from '@angular/platform-browser';

interface Msg { id: string; from: string; text: string; }

@Component({
  selector: 'app-chat-ui',
  template: `
    <div style="width: 340px; border: 1px solid #cbd5e1; border-radius: 12px; overflow: hidden;">
      <div #log style="height: 280px; overflow-y: auto; padding: 12px; background: #f8fafc;">
        <div
          *ngFor="let m of messages"
          [style.justify-content]="m.from === 'me' ? 'flex-end' : 'flex-start'"
          style="display: flex; margin-bottom: 8px;"
        >
          <div
            [style.background]="m.from === 'me' ? '#2563eb' : '#e2e8f0'"
            [style.color]="m.from === 'me' ? '#fff' : '#111'"
            style="max-width: 75%; padding: 8px 12px; border-radius: 14px;"
          >{{ m.text }}</div>
        </div>
      </div>
      <div style="display: flex; gap: 8px; padding: 10px; border-top: 1px solid #e5e7eb;">
        <input
          [value]="draft"
          (input)="draft = $any($event.target).value"
          (keydown.enter)="send()"
          placeholder="Type a message…"
          style="flex: 1; padding: 8px; border: 1px solid #cbd5e1; border-radius: 8px;"
        />
        <button (click)="send()" style="padding: 8px 16px; cursor: pointer; background: #2563eb; color: #fff; border: none; border-radius: 8px;">Send</button>
      </div>
    </div>
  `,
})
export class ChatUiComponent implements AfterViewChecked {
  messages: Msg[] = [{ id: 'm0', from: 'them', text: 'Hey! Ask me anything.' }];
  draft = '';
  private n = 0;

  @ViewChild('log') log!: ElementRef<HTMLElement>;

  uid(): string {
    this.n++;
    return 'm' + this.n;
  }

  send(): void {
    const t = this.draft.trim();
    if (!t) {
      return;
    }
    this.messages.push({ id: this.uid(), from: 'me', text: t });
    this.draft = '';
    setTimeout(() => {
      this.messages.push({ id: this.uid(), from: 'them', text: 'Echo: ' + t });
    }, 600);
  }

  ngAfterViewChecked(): void {
    if (this.log) {
      const el = this.log.nativeElement;
      el.scrollTop = el.scrollHeight;
    }
  }
}

@Component({
  selector: 'app-root',
  template: `
    <div style="font-family: sans-serif; padding: 20px;">
      <h1>Chat UI Demo</h1>
      <app-chat-ui></app-chat-ui>
    </div>
  `,
})
export class AppComponent {}

@NgModule({
  declarations: [AppComponent, ChatUiComponent],
  imports: [BrowserModule],
  bootstrap: [AppComponent],
})
export class AppModule {}
